{
  "contract_title": "Master Services Agreement",
  "parties": ["Acme Corp", "Globex LLC"],
  "clauses": {
    "termination": {
      "present": true,
      "text": "Either party may terminate this Agreement upon 30 days written notice."
    },
    "indemnification": {
      "present": true,
      "text": "Each party shall indemnify the other against third-party claims arising from breach of this Agreement."
    },
    "governing_law": {
      "present": true,
      "text": "This Agreement shall be governed by the laws of the State of Delaware."
    },
    "confidentiality": {
      "present": true,
      "text": "Each party shall maintain the confidentiality of the other party's proprietary information for a period of five years."
    }
  }
}
